import { Glob } from "bun";
import fs from "node:fs";
import path from "node:path";

const LOCALES_DIR = "src/locales";
const LOCALES_BARREL = path.join(LOCALES_DIR, "index.ts");

const glob = new Glob("*.json");
const localeFiles = Array.from(glob.scanSync(LOCALES_DIR)).sort();
const locales = localeFiles.map((f) => path.basename(f, ".json"));

export function generateLocaleBarrel() {
  const lines = [
    "// This file is automatically generated. Do not edit it manually.",
    ...locales.map((l) => `import ${l} from "./${l}.json";`),
    "",
    `export const SUPPORTED_LOCALES = [${locales.map((l) => `"${l}"`).join(", ")}] as const;`,
    `export type SupportedLocale = (typeof SUPPORTED_LOCALES)[number];`,
    "",
    `const dictionaries: Record<SupportedLocale, Record<string, string>> = {`,
    ...locales.map((l) => `  ${l},`),
    `};`,
    "",
    `export default dictionaries;`,
    "",
  ];
  try {
    fs.writeFileSync(LOCALES_BARREL, lines.join("\n"), "utf-8");
  } catch (e) {
    console.error("Failed to generate locale barrel: ", e);
  }
}

generateLocaleBarrel();

const isWatch = Bun.argv.includes("--watch");

if (isWatch) {
  console.log("👀 Watching src/locales for changes...");
  fs.watch(LOCALES_DIR, { recursive: true }, (_eventType, filename) => {
    if (filename && filename.endsWith(".json")) {
      console.log(`file changed: ${filename} Rebuilding...`);
      generateLocaleBarrel();
    }
  });
}
